curl -sL --max-time 90 "https://arxiv.org/abs/2601.18267" -o /tmp/adore_abs.html; echo "--- abs len: $(wc -c </tmp/adore_abs.html)"; grep -o -i -E "[^<>]{0,200}(50\.0|human[- ]written|calibrat|reference)[^<>]{0,200}" /tmp/adore_abs.html | head -20; echo "=== HTML full text ==="; curl -sL --max-time 90 "https://arxiv.org/html/2601.18267v1" -o /tmp/adore.html; echo "len: $(wc -c </tmp/adore.html)"; python3 - <<'EOF'
import re,html
try:
    t=open('/tmp/adore.html',encoding='utf-8',errors='replace').read()
except Exception as e:
    print(e); raise SystemExit
txt=re.sub(r'<[^>]+>',' ',t); txt=html.unescape(txt); txt=re.sub(r'\s+',' ',txt)
print("TEXTLEN",len(txt))
for kw in ['50.0','calibrat','human-written','human written','reference','rank #1','ranks first','52.65','Tavily','LangChain','leaderboard']:
    for m in re.finditer(re.escape(kw),txt,re.I):
        print(f"[{kw}] ...{txt[max(0,m.start()-180):m.start()+220]}...")
        print("---")
EOF
